import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"枪弹使","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/6.一次性血统/枪弹使.md","filePath":"4.资源分区/1.血统与训练/6.一次性血统/枪弹使.md"}'),o={name:"4.资源分区/1.血统与训练/6.一次性血统/枪弹使.md"};function b(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"枪弹使",tabindex:"-1"},[n("枪弹使 "),r("a",{class:"header-anchor",href:"#枪弹使","aria-label":'Permalink to "枪弹使"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD勿忘尘002")])])],-1),s('<h1 id="枪弹使-1" tabindex="-1">枪弹使 <a class="header-anchor" href="#枪弹使-1" aria-label="Permalink to &quot;枪弹使&quot;">​</a></h1><p>枪弹使<br> D+600<br> 一次性血统<br> 枪弹使是对使用精神力操纵子弹的异能者的统称。他们通过改变子弹弹道，改变子弹结构等方式增强子弹的杀伤力，这意味着枪弹使必须搭配具有【子弹】概念的枪械才能使用其下属能力。</p><p>获得枪弹使血统会打开一个精神力能量池，获得【弱点看破】、【强力子弹】、【精确打击】三个特性，并开启枪弹使下属技能购买权。<br> 弱点看破：在购买时，从反射豁免、强韧豁免、意志豁免中选择一种，你总是能看到你希望看到的角色的那种豁免的数据，这视为一种D级别心灵来源的读卡能力。<br> 强力子弹：你的枪械射出的子弹将不会在末端再失去力量，现在，当你试图计算极限射程时，将不会承受任何环境减值。<br> 精确打击：当你进行一次针对特殊部位的枪械射击时，可以再消耗1点精神力，至多抵消这次部位攻击中的2点部位攻击减值。</p><p>枪弹使下属技能：<br> 离奇轨迹<br> D+500<br> 你可以在一次枪械射击中消耗1点精神力，用意念操控子弹的弹道，让被发射的子弹变得飘忽离奇，本次攻击获得【刁钻】，并再获得等同于使用枪械最高支线等级*2的高速（D1C2B3A4S5）。</p><p>爆裂子弹<br> D+500<br> 你可以在一次枪械射击中消耗2点精神力，让你发射出的子弹在敌人体内炸裂开来。本次攻击额外附带1点不可豁免的流血点数。你可以支付8XP，让这个数值上升1点，但至多不能超过你当前使用的枪械的最高支线等级*2（D1C2B3A4S5）。（例：玩家愚者花费了32XP购买4次，他的射击将附带4点不可豁免的流血点数，但他使用的是一把D级枪械，因此他的攻击至多只会附带2点不可豁免的流血点数，即使他花费了32XP）</p><p>不可视子弹<br> D+500<br> 你可以在一次枪械射击中消耗1点精神力，将射出的子弹变为不可视子弹，这并不意味着这枚子弹真的不可视，而是通过扭曲周围空间让它难以察觉，不可视子弹将会对被攻击者具有C级措手不及的效果。</p><p>歌莉娅之殇<br> D+500<br> 你可以通过精神力轻松找出巨大敌人的弱点，在对体积超过7点的非载具敌人进行枪械射击时，你可以消耗1点精神力，被攻击的目标每在7体积的基础上提升2点，你就忽略其1点特殊部位上的减值，你抵消其2点特殊部位上的减值，若你的忽略/抵消部位上的减值超出了部位减值的值，则忽略每超出1点变为1点、抵消每超出1点变为2点这次攻击上的表现加值。</p><p>夺命连发<br> D+500<br> 你可以在一次枪械射击中消耗1点精神力，将这次攻击提升为连射，若已经是连射，则改为获得2点这次攻击检定上的表现加值。同时，被你攻击的目标视为已经被额外攻击了3次一般承受本次攻击。</p><p>孪生子弹<br> 1000<br> 你可以在一次枪械射击中消耗1点精神力，同时对射程范围内的另一个目标射出一发相同的子弹。同时，这次射击视为具有【贯穿】一般进行结算。</p><hr><p>Copyright 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg勿忘尘</a>. All Rights Reserved.</p>',11)])])}const f=a(o,[["render",b]]);export{D as __pageData,f as default};
